export type AgentJobStatus="PENDING"|"CLAIMED"|"RUNNING"|"RETRY_SCHEDULED"|"SUCCEEDED"|"FAILED"|"CANCELLED"|"DEAD_LETTER"|"CANCELLING"|"CANCEL_STUCK";
export type CancellationAttemptOutcome="FAILED"|"TIMED_OUT"|"REJECTED";
export type CancellationConfirmationKind="RUNTIME_CANCEL_CONFIRMED"|"RUNTIME_STATUS_CANCELLED"|"RUNTIME_TERMINAL_OBSERVED"|"PROCESS_TERMINATED"|"RECOVERY_CONFIRMED";
export interface AgentJobAssignmentBinding {readonly assignmentId:string;readonly agentId:string;readonly agentKey:string;readonly agentVersion:number;}
export interface AgentJobClaim { readonly status?:AgentJobStatus;readonly jobId:string;readonly projectId:string;readonly task:AgentTask;readonly assignment?:AgentJobAssignmentBinding;readonly workerId:string;readonly claimId:string;readonly fencingToken:number;readonly leaseGeneration:number;readonly jobVersion:number;readonly leaseExpiresAt:Date;readonly retryCount:number;readonly maxRetries:number;readonly cancelRequested:boolean;readonly cancellationRequestId:string|null;readonly cancellationSequence:number|null;readonly completionSequence:number|null;readonly runtimeWatermark:number;readonly cancelAttemptCount:number;readonly cancelMaxAttempts:number;readonly cancelRemainingAttempts:number;readonly cancelLastOutcome:CancellationAttemptOutcome|"CONFIRMED"|null;readonly cancelLastErrorCode:string|null;readonly cancelConfirmedAt:Date|null;readonly cancelConfirmationKind:CancellationConfirmationKind|null; }
