export interface AgentJobPrestartGuard { readonly jobVersion:number;readonly leaseGeneration:number;readonly workerId:string|null;readonly claimId:string|null;readonly fencingToken:number|null; }
export interface EnqueueAgentJob { readonly task:AgentTask;readonly messageId:string;readonly consumerIdentity:string;readonly idempotencyKey:string;readonly requestDigest:string;readonly traceId:string;readonly maxRetries:number; }
export interface AgentJobStatusView { readonly jobId:string;readonly projectId:string;readonly runId:string;readonly status:AgentJobStatus;readonly jobVersion:number;readonly leaseGeneration:number;readonly retryCount:number;readonly maxRetries:number;readonly fencingToken:number|null;readonly result:AgentResult|null;readonly cancelRequested:boolean;readonly cancellationRequestId:string|null;readonly cancellationSequence:number|null;readonly completionSequence:number|null;readonly cancelAttemptCount:number;readonly cancelMaxAttempts:number;readonly cancelRemainingAttempts:number;readonly cancelLastOutcome:CancellationAttemptOutcome|"CONFIRMED"|null;readonly cancelLastErrorCode:string|null;readonly cancelConfirmedAt:Date|null;readonly cancelConfirmationKind:CancellationConfirmationKind|null; }
export class AgentJobLateResultAlreadyCommittedError extends Error {readonly code="AGENT_JOB_LATE_RESULT_ALREADY_COMMITTED";constructor(){super("AGENT_JOB_LATE_RESULT_ALREADY_COMMITTED");this.name="AgentJobLateResultAlreadyCommittedError";}}
type Queryable=Pick<Pool,"connect"|"query">;
export interface AgentJobSession {query<R extends QueryResultRow=QueryResultRow>(sql:string,values?:readonly unknown[]):Promise<{rows:R[];rowCount:number|null}>;}
interface JobRow { id:string;project_id:string;status:AgentJobStatus;job_version:string;lease_generation:string;retry_count:number;max_retries:number;lease_owner:string|null;claim_idempotency_key:string|null;fencing_token:string|null;lease_expires_at:Date|null;cancel_requested_at:Date|null;cancellation_request_id:string|null;cancellation_sequence:string|null;completion_sequence:string|null;cancellation_runtime_watermark:string;cancel_attempt_count:number;cancel_max_attempts:number;cancel_remaining_attempts:number;cancel_last_outcome:CancellationAttemptOutcome|"CONFIRMED"|null;cancel_last_error_code:string|null;cancel_confirmed_at:Date|null;cancel_confirmation_kind:CancellationConfirmationKind|null;agent_run_id:string;agent_attempt_id:string;result_payload:unknown|null;schema_version:number;task_id:string;attempt_id:string;run_id:string;role:AgentTask["role"];scenario:AgentTask["scenario"];input_ref:string;repair_ordinal:number;assignment_id:string|null;assignment_agent_id:string|null;assignment_agent_key:string|null;assignment_agent_version:number|null; }
interface CompletionRow extends JobRow {assignment_status:"ASSIGNED"|"RELEASED"|null;agent_result_id:string|null;terminal_at:Date|null;run_state:string;run_result_id:string|null;run_terminal_at:Date|null;}
interface CompletionEvidenceRow {evidence_id:string;evidence_type:string;evidence_digest:string;attestation_payload_digest:string;runtime_event_sequence:string;terminal_state:string;candidate:unknown;validity:"VALID"|"REJECTED";consumed_at:Date|null;consumed_job_version:string|null;job_id:string;cancellation_request_id:string;lease_generation:string;fencing_token:string;}
