  private isImmediateCancellationSuccessor(row:CompletionRow,context:CompleteAgentJobContext|ConfirmCancelledAgentJobContext):boolean{return context.operation==="COMPLETE"&&row.status==="CANCELLING"&&row.cancel_requested_at!==null&&row.cancellation_request_id!==null&&row.cancellation_sequence!==null&&row.completion_sequence===null&&row.agent_result_id===null&&row.terminal_at===null&&Number(row.job_version)===context.jobVersion+1&&Number(row.cancellation_sequence)===Number(row.job_version)&&row.lease_owner===context.workerId&&row.claim_idempotency_key===context.claimId&&Number(row.fencing_token)===context.fencingToken&&Number(row.lease_generation)===context.leaseGeneration;}
